-- Vintage Hall — demo seed for supabase/schema.sql
-- Run ONCE in the Supabase SQL Editor AFTER schema.sql.
-- Mirrors src/data/products.ts so client lot ids match DB rows (bids FK needs them).
-- Auction end_time values are relative to seeding time, matching the client's hoursFromNow offsets.

insert into public.products
  (id, icon, category, sale_type, photo, extra_photos, name, era, description,
   price, start_price, current_bid, bid_step, end_time,
   origin, condition_grade, dimensions, weight, rarity, badge, certified)
overriding system value
values
