  (12, 'figurine', 'porcelain', 'shop', '/images/products/little-hostess-pair.jpg', array['/images/products/little-hostess-mark.jpg'], '{"uk":"Парні статуетки «Маленька хазяйка»","en":"Pair of \"Little Hostess\" Figurines","pl":"Para figurek „Mała Gospodyni”","ru":"Парные статуэтки «Маленькая хозяйка»"}'::jsonb, '{"uk":"1958 р.","en":"1958","pl":"1958","ru":"1958 г."}'::jsonb, '{"uk":"Фарфорові статуетки узбечок із чайником, Дулевський завод, скульптор О. М. Богданова. На дні — заводське клеймо та маркування «2С-58г», що підтверджує рік випуску. Яскравий ручний розпис із золоченням, парний комплект у гарному стані.","en":"Porcelain figurines of Uzbek girls with teapots, Dulevo Factory, sculptor O. M. Bogdanova. The base bears the factory mark and \"2С-58г\" code confirming the year of production. Bright hand-painted decoration with gilding, a matched pair in good condition.","pl":"Porcelanowe figurki uzbeckich dziewczynek z czajnikami, fabryka Dulewo, autorstwa O. M. Bogdanowej. Na spodzie widoczny znak fabryczny oraz kod „2С-58г” potwierdzający rok produkcji. Jaskrawe, ręcznie malowane zdobienia ze złoceniem, kompletna para w dobrym stanie.","ru":"Фарфоровые статуэтки узбечек с чайником, Дулёвский завод, скульптор О. М. Богданова. На дне — заводское клеймо и маркировка «2С-58г», подтверждающая год выпуска. Яркая ручная роспись с золочением, парный комплект в хорошем состоянии."}'::jsonb, 5000, null, null, null, null, 'СРСР', 'Дуже добрий', '16 × 11 см (кожна)', '420 г (пара)', 'rare', 'certified', true),
  (13, 'painting', 'painting', 'shop', 'https://picsum.photos/seed/steppe-painting/600/450', null, '{"uk":"Степовий пейзаж","en":"Steppe Landscape","pl":"Pejzaż stepowy","ru":"Степной пейзаж"}'::jsonb, '{"uk":"Кін. XIX ст.","en":"Late 19th c.","pl":"Kon. XIX w.","ru":"Кон. XIX в."}'::jsonb, '{"uk":"Олія, полотно, академічна школа. Підпис художника в правому нижньому куті, авторство атрибутовано експертом галереї.","en":"Oil on canvas, academic school. Artist''s signature in the lower right corner, attribution confirmed by a gallery expert.","pl":"Olej na płótnie, szkoła akademicka. Podpis artysty w prawym dolnym rogu, autorstwo potwierdzone przez eksperta galerii.","ru":"Масло, холст, академическая школа. Подпись художника в правом нижнем углу, авторство атрибутировано экспертом галереи."}'::jsonb, 8500, null, null, null, null, 'Україна', 'Добра, кракелюр лаку', '54 × 38 см (у рамі)', '1.8 кг', 'rare', 'expert', true),
