  (15, 'ring', 'jewelry', 'shop', 'https://picsum.photos/seed/silver-brooch/600/450', null, '{"uk":"Срібна брошка з бірюзою","en":"Silver Brooch with Turquoise","pl":"Srebrna broszka z turkusem","ru":"Серебряная брошь с бирюзой"}'::jsonb, '{"uk":"Поч. XX ст.","en":"Early 20th c.","pl":"Pocz. XX w.","ru":"Нач. XX в."}'::jsonb, '{"uk":"Срібло 875-ї проби, авторська філігрань, природна бірюза без обробки.","en":"875 silver, signed filigree work, natural untreated turquoise.","pl":"Srebro próby 875, autorska filigran, naturalny, nieobrobiony turkus.","ru":"Серебро 875-й пробы, авторская филигрань, природная бирюза без обработки."}'::jsonb, 3200, null, null, null, null, 'Україна', 'Дуже добрий', '5 × 3 см', '14 г', 'unique', 'certified', true)
on conflict (id) do nothing;

-- keep the identity counter above the seeded ids
select setval(pg_get_serial_sequence('public.products', 'id'), (select max(id) from public.products));

-- realtime for live bidding (safe to re-run)
do $$
begin
  alter publication supabase_realtime add table public.bids;
exception when duplicate_object then null;
end $$;
do $$
begin
  alter publication supabase_realtime add table public.products;
exception when duplicate_object then null;
end $$;

